import{_ as a,o as t,c as s,j as r,a as n,a1 as b}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"你要撞大运咯","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/杂项/你要撞大运咯.md","filePath":"4.资源分区/6.技艺及称号/杂项/你要撞大运咯.md"}'),o={name:"4.资源分区/6.技艺及称号/杂项/你要撞大运咯.md"};function d(p,e,_,l,i,c){return t(),s("div",null,[...e[0]||(e[0]=[r("h1",{id:"你要撞大运咯",tabindex:"-1"},[n("你要撞大运咯 "),r("a",{class:"header-anchor",href:"#你要撞大运咯","aria-label":'Permalink to "你要撞大运咯"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风027")])])],-1),b('<h1 id="你要撞大运咯-1" tabindex="-1">你要撞大运咯 <a class="header-anchor" href="#你要撞大运咯-1" aria-label="Permalink to &quot;你要撞大运咯&quot;">​</a></h1><p>你要撞大运了<br> B+2000<br> “撞大运”有时被用来描述主角因为某种意外（如被卡车撞）而穿越到异世界，从而获得非凡的机遇和能力。这种说法通常带有幽默和讽刺的意味。（认真脸）<br> 但是！<br> 这里是主神空间！<br> 撞大运不会给予目标任何什么机遇和能力，而是实实在在的撞大运（严肃）！</p><p>【你要撞大运咯！】这种技艺其实只是在你自身原有攻击之上覆盖一层特别的效果而已，或者说具象化大运！<br> 你在购买该技艺时选择绑定任意一种攻击方式（射击，施法，肉搏，白刃等……）。每当你使用绑定的攻击方式时，无论是用拳打，还是用刀或者施法射击时，一辆大运牌大卡车会从一旁或者直接从你手中具现出一个巨大的卡车头猛然冲撞你的攻击目标，这次攻击视为一次招式，同时这次攻击附带成功数一半的B级信息来源的肢体妨碍点数，目标以强韧豁免对抗攻击出目，同时具有【碾压】特性，以及附带一次冲撞。<br> 部分效果视觉例子：<br> ①如果是肉搏或者白刃，表现形式为，手中出现极大的卡车头！（可以在购买时替换为压路机）<br> ②如果是施法或者射击，表现形式为，挥手间或者扣动扳机，敌人突然间被一辆不知从何处的卡车猛然撞飞。<br> ps：只要合理即可，大家伙可以发挥想象力来创造效果场景，一般来说可以和st协商完成一些高难度场景还原。</p><p>扩展技艺树<br> ——————————————————————<br> 【能帮我看看前车灯吗？】<br> C+1000<br> 你可以随意使用自由动作对某个目标说出“我的前半挂车灯坏了，能帮我看看吗？”<br> 如果对方在你说完后，在之后一轮走入你触及范围内，那么你对其使用的第一次你要撞大运咯！时拥有C级措手不及效果，并且这次攻击获得10点威猛。<br> 注意：每轮只能朝一个目标说出这句话。</p><p>【装逼？让你飞起来！】<br> C+1000<br> 你现在可以以一个标准动作立马召唤一辆大运牌卡车，你直接进入驾驶室，开始启动发动机，卡车头发出括噪的发动机转动声，当然这个其实只是某种意义上的幻象，不会为你提供任何遮蔽或者防御效果。<br> 在下一轮你必须冲锋一个目标，否则卡车会自动消散，你会直接摔落在地。<br> 在这次冲锋中你可以使用【你要撞大运咯！】的效果，同时这次冲锋距离增加60米，受到伤害的目标需要进行一次反射豁免，DC为伤害值，失败则在一轮内陷入B级别、创伤来源的击飞状态。<br> 如果你脸上表情狰狞，尽显邪恶本质，还发出奇怪的桀桀桀笑声，那么你这次攻击额外获得8点增强加值。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',7)])])}const m=a(o,[["render",d]]);export{f as __pageData,m as default};
